-- Seed intel_demo_corpus table for search functionality
-- All data is 100% synthetic/fictional
-- Run via: Get-Content seed-intel-demo-corpus.sql | docker exec -i intelforge-postgres psql -U intelforge -d intelforge

BEGIN;

INSERT INTO intel_demo_corpus (id, timestamp, doc_type, source_name, source_kind, title, summary, body, severity, risk_score, confidence, tlp, tags, entities, iocs, relationships, raw_reference, safe_demo, redaction_level)
VALUES
  -- MetaCorp breach entries
  ('demo-evt-meta-001', NOW()-INTERVAL '45 days', 'breach', 'Demo Feed', 'synthetic', 'MetaCorp confirms 2.9B record breach — largest social media leak in history', 'MetaCorp platform database containing 2.9 billion user records posted on darkweb forum.', 'MetaCorp platform database containing 2.9 billion user records posted on darkweb forum. Data includes emails, hashed passwords, phone numbers, and profile IDs. Demo dataset. Breach vector: CVE-2026-99001 (MetaCorp Fileshare Pro RCE). Threat actor: DEMO-APT-01 linked via stealer logs (Raccoon). C2: 198.51.100.50.', 'critical', 95, 92, 'TLP:CLEAR', ARRAY['meta','breach','social-media','2.9b-records','demo'], jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','domain','value','facebook-demo.invalid'),jsonb_build_object('type','cve','value','CVE-2026-99001'),jsonb_build_object('type','actor','value','DEMO-APT-01')), jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','ip','value','198.51.100.50')), jsonb_build_array(jsonb_build_object('type','attributed_to','value','DEMO-APT-01'),jsonb_build_object('type','exploits_cve','value','CVE-2026-99001')), '{}'::jsonb, true, 'synthetic'),

  ('demo-evt-meta-002', NOW()-INTERVAL '43 days', 'ioc', 'Demo Feed', 'synthetic', 'MetaCorp breach IOCs: domain meta-corp.invalid, IP 198.51.100.50, hash deadbeef...', 'Indicators of compromise from MetaCorp breach linked to threat actor DEMO-APT-01.', 'IOCs from MetaCorp breach: domain=meta-corp.invalid, IP=198.51.100.50 (C2 server), SHA256=deadbeef0000000000000000000000000000000000000000000000000000000001 (meta_webshell.php), malware_family=DEMO-WEBSHELL-01. Linked to CVE-2026-99001 exploitation. Stealer logs captured admin credentials 6 days before breach.', 'critical', 93, 95, 'TLP:CLEAR', ARRAY['meta','ioc','c2','malware','demo'], jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','ip','value','198.51.100.50'),jsonb_build_object('type','sha256','value','deadbeef0000000000000000000000000000000000000000000000000000000001'),jsonb_build_object('type','malware','value','DEMO-WEBSHELL-01')), jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','ip','value','198.51.100.50')), jsonb_build_array(jsonb_build_object('type','c2_for','value','meta-corp.invalid')), '{}'::jsonb, true, 'synthetic'),

  ('demo-evt-meta-003', NOW()-INTERVAL '44 days', 'vulnerability', 'Demo Feed', 'synthetic', 'CVE-2026-99001: MetaCorp Fileshare Pro remote code execution via unauthenticated file upload', 'Critical RCE vulnerability in MetaCorp Fileshare Pro actively exploited by DEMO-APT-01 and DEMO-RANSOM-01.', 'CVE-2026-99001 affects MetaCorp Fileshare Pro. CVSS 9.8 CRITICAL. Unauthenticated file upload via /api/upload endpoint allows remote code execution. Webshell drops at /uploads/shell.php. Actively exploited by DEMO-APT-01 for MetaCorp breach and by DEMO-RANSOM-01 for double-extortion. Added to CISA KEV catalog.', 'critical', 98, 97, 'TLP:CLEAR', ARRAY['cve','meta','rce','exploit','kev','demo'], jsonb_build_array(jsonb_build_object('type','cve','value','CVE-2026-99001'),jsonb_build_object('type','vendor','value','MetaCorp'),jsonb_build_object('type','product','value','FileShare Pro'),jsonb_build_object('type','actor','value','DEMO-APT-01'),jsonb_build_object('type','actor','value','DEMO-RANSOM-01')), jsonb_build_array(jsonb_build_object('type','cve','value','CVE-2026-99001')), jsonb_build_array(jsonb_build_object('type','exploited_by','value','DEMO-APT-01'),jsonb_build_object('type','exploited_by','value','DEMO-RANSOM-01')), '{"cvss_v3_score":9.8,"cvss_v3_severity":"CRITICAL","epss_score":0.96,"is_kev":true}'::jsonb, true, 'synthetic'),

  ('demo-evt-meta-004', NOW()-INTERVAL '44 days', 'stealer', 'Demo Feed', 'synthetic', 'Stealer logs show MetaCorp credentials harvested before breach', 'Raccoon stealer captured MetaCorp employee credentials 6 days before the breach.', 'Stealer telemetry from meta-host-001 (Windows 11, US): Raccoon stealer captured 234 credentials including admin.meta@demo.invalid, dev.team@demo.invalid, cloudops@demo.invalid. VPN portal (vpn.meta-corp.invalid), FileShare admin (fileshare.meta-corp.invalid), and cloud dashboard (cloud.meta-corp.invalid) credentials captured. These were used as initial access for CVE-2026-99001 exploitation.', 'high', 88, 93, 'TLP:CLEAR', ARRAY['stealer','meta','raccoon','credentials','demo'], jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','stealer','value','raccoon'),jsonb_build_object('type','cve','value','CVE-2026-99001')), jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','ip','value','198.51.100.50')), jsonb_build_array(jsonb_build_object('type','harvested_credentials_for','value','meta-corp.invalid')), '{"stealer_family":"raccoon","credential_count":234,"matched_domains":["meta-corp.invalid","facebook-demo.invalid","instagram-demo.invalid"]}'::jsonb, true, 'masked'),

  -- JPMorgan Demo entries
  ('demo-evt-jpm-001', NOW()-INTERVAL '35 days', 'breach', 'Demo Feed', 'synthetic', 'JPMorgan Demo Bank internal network access confirmed compromised', 'ALPHV/BlackCat ransomware group claims access to JPMorgan Demo Bank internal network.', 'JPMorgan Demo Bank internal network compromised by ALPHV/BlackCat. Full internal network access confirmed. Can access trading systems (trading.jpmorgan-demo.invalid), risk dashboards (risk.jpmorgan-demo.invalid), and internal communications. Bloomberg Terminal credentials captured from Vidar stealer logs (jpm-host-002). Domain admin from jpm-host-003 (raccoon, 298 creds). Darkweb auction started at $75K.', 'critical', 96, 95, 'TLP:CLEAR', ARRAY['jpmorgan','breach','financial','alphv','trading','demo'], jsonb_build_array(jsonb_build_object('type','domain','value','jpmorgan-demo.invalid'),jsonb_build_object('type','actor','value','ALPHV/BlackCat'),jsonb_build_object('type','cve','value','CVE-2026-99992')), jsonb_build_array(jsonb_build_object('type','domain','value','jpmorgan-demo.invalid'),jsonb_build_object('type','ip','value','203.0.113.200')), jsonb_build_array(jsonb_build_object('type','victim_of','value','ALPHV/BlackCat'),jsonb_build_object('type','compromised_by','value','raccoon-stealer')), '{}'::jsonb, true, 'synthetic'),

  ('demo-evt-jpm-002', NOW()-INTERVAL '34 days', 'stealer', 'Demo Feed', 'synthetic', 'Vidar stealer captures JPMorgan Demo trading credentials', '6 compromised hosts in JPMorgan Demo environment captured sensitive trading credentials.', 'Vidar stealer logs from jpm-host-002 (Windows 11, US): trader.senior@demo.invalid captured from trading.jpmorgan-demo.invalid. Bloomberg Terminal session cookies harvested. jpm-host-004 (RedLine): bloomberg.user@demo.invalid from bloomberg.jpmorgan-demo.invalid. jpm-host-003 (Raccoon): it.operations@demo.invalid from intranet.jpmorgan-demo.invalid. Domain admin level access confirmed. jpm-host-006 (Stealc): api.trading@demo.invalid from api.jpmorgan-demo.invalid.', 'high', 90, 92, 'TLP:CLEAR', ARRAY['stealer','vidar','jpmorgan','trading','bloomberg','demo'], jsonb_build_array(jsonb_build_object('type','domain','value','jpmorgan-demo.invalid'),jsonb_build_object('type','stealer','value','vidar')), jsonb_build_array(jsonb_build_object('type','domain','value','jpmorgan-demo.invalid')), jsonb_build_array(jsonb_build_object('type','captured_credentials_from','value','jpmorgan-demo.invalid')), '{"stealer_family":"vidar","credential_count":145,"matched_domains":["jpmorgan-demo.invalid","portal.jpmorgan-demo.invalid"]}'::jsonb, true, 'masked'),

  ('demo-evt-jpm-003', NOW()-INTERVAL '40 days', 'vulnerability', 'Demo Feed', 'synthetic', 'CVE-2026-99992: JPMorgan Demo trading platform SQL injection', 'Critical SQL injection in JPMorgan Demo trading platform exploited by DEMO-APT-02.', 'CVE-2026-99992 affects JPMorgan Demo trading platform. CVSS 9.1 CRITICAL. SQL injection in order submission endpoint allows database access. Linked to JPMorgan Demo Bank breach by DEMO-APT-02 actor. Exploit: order parameter not sanitized, UNION-based injection returns full DB. ALPHV/BlackCat used this as initial access vector.', 'critical', 97, 94, 'TLP:CLEAR', ARRAY['cve','jpmorgan','sql-injection','trading','demo'], jsonb_build_array(jsonb_build_object('type','cve','value','CVE-2026-99992'),jsonb_build_object('type','vendor','value','JPMorgan'),jsonb_build_object('type','product','value','Trading Platform'),jsonb_build_object('type','actor','value','DEMO-APT-02'),jsonb_build_object('type','actor','value','ALPHV/BlackCat')), jsonb_build_array(jsonb_build_object('type','cve','value','CVE-2026-99992')), jsonb_build_array(jsonb_build_object('type','exploited_by','value','DEMO-APT-02'),jsonb_build_object('type','exploited_by','value','ALPHV/BlackCat')), '{"cvss_v3_score":9.1,"cvss_v3_severity":"CRITICAL","epss_score":0.89,"is_kev":true}'::jsonb, true, 'synthetic'),

  -- Google Demo entries
  ('demo-evt-google-001', NOW()-INTERVAL '55 days', 'cloud_exposure', 'Demo Feed', 'synthetic', 'Google Demo GCP service account keys exposed on GitHub and darkweb', 'NEXUS-THREAT group exploiting Google Demo cloud environment via exposed service account keys.', 'Google Demo GCP service account keys found exposed: gh-google-001: CDK pipeline in google-demo-infrastructure/terraform (gcp_service_account_key, critical, still exposed). gh-google-002: prod.env in google-demo-config/cloud-run (google_api_key, high). gh-google-003: train.py in google-demo-ml/pipeline (google_oauth_token, critical). NEXUS-STEALER-01 (google_stealer.py) captures GCP credentials and beacons to 198.51.100.75. C2 beacon pattern detected in google-host-001.', 'high', 88, 91, 'TLP:CLEAR', ARRAY['google','gcp','cloud','nexus-threat','github','demo'], jsonb_build_array(jsonb_build_object('type','domain','value','google-demo.invalid'),jsonb_build_object('type','ip','value','198.51.100.75'),jsonb_build_object('type','actor','value','NEXUS-THREAT'),jsonb_build_object('type','malware','value','NEXUS-STEALER-01')), jsonb_build_array(jsonb_build_object('type','domain','value','google-demo.invalid'),jsonb_build_object('type','ip','value','198.51.100.75')), jsonb_build_array(jsonb_build_object('type','compromised_by','value','NEXUS-THREAT'),jsonb_build_object('type','exposed_on','value','github')), '{"github_repo":"google-demo-infrastructure","secret_type":"gcp_service_account_key","risk_level":"critical","still_exposed":true}'::jsonb, true, 'synthetic'),

  -- Microsoft Demo entries
  ('demo-evt-ms-001', NOW()-INTERVAL '48 days', 'breach', 'Demo Feed', 'synthetic', 'Microsoft Demo Azure AD global admin credentials found in darkweb market', 'LockBit ransomware affiliate selling Microsoft Demo Azure AD global admin access.', 'Microsoft Demo Azure AD global admin credentials for microsoft-demo.invalid tenant found in darkweb market (LockBit affiliate). admin@microsoft-demo.invalid password captured by Raccoon stealer (ms-host-001). Can access Azure Portal, DevOps, and all SaaS apps. tenant_id=DEMO-CORP. LockBit affiliate started auction at $20K. DevOps credentials (devops@microsoft-demo.invalid) from RedLine (ms-host-002) give Project Collection Admin access.', 'critical', 94, 93, 'TLP:CLEAR', ARRAY['microsoft','azure','lockbit','global-admin','demo'], jsonb_build_array(jsonb_build_object('type','domain','value','microsoft-demo.invalid'),jsonb_build_object('type','actor','value','LockBit'),jsonb_build_object('type','cve','value','CVE-2026-99993')), jsonb_build_array(jsonb_build_object('type','domain','value','microsoft-demo.invalid')), jsonb_build_array(jsonb_build_object('type','victim_of','value','LockBit'),jsonb_build_object('type','compromised_by','value','raccoon-stealer')), '{}'::jsonb, true, 'synthetic'),

  -- Amazon Demo entries
  ('demo-evt-aws-001', NOW()-INTERVAL '50 days', 'cloud_exposure', 'Demo Feed', 'synthetic', 'Amazon Demo AWS credentials with AdministratorAccess policy exposed', 'NEXUS-THREAT group targeting Amazon Demo AWS environment via exposed credentials.', 'Amazon Demo AWS credentials exposed: Root account (Christopher Lee) credentials found in paste site and Stealc stealer. Full AWS account access, no MFA. gh-aws-001: CDK pipeline in amazon-demo-infra/cdk-pipeline (aws_access_key, critical, still exposed). gh-aws-002: deploy.yml in amazon-demo-cicd/pipeline (aws_secret_key, critical). NEXUS-STEALER-02 (aws_keylogger.exe) targets AWS credentials and beacons to 198.51.100.100. Full cloud environment compromise confirmed.', 'critical', 92, 90, 'TLP:CLEAR', ARRAY['amazon','aws','nexus-threat','cloud','root-account','demo'], jsonb_build_array(jsonb_build_object('type','domain','value','amazon-demo.invalid'),jsonb_build_object('type','ip','value','198.51.100.100'),jsonb_build_object('type','actor','value','NEXUS-THREAT')), jsonb_build_array(jsonb_build_object('type','domain','value','amazon-demo.invalid'),jsonb_build_object('type','ip','value','198.51.100.100')), jsonb_build_array(jsonb_build_object('type','compromised_by','value','NEXUS-THREAT')), '{"aws_access_type":"AdministratorAccess","region":"us-east-1","root_compromised":true}'::jsonb, true, 'synthetic'),

  -- Cross-company APT campaigns
  ('demo-evt-apt-001', NOW()-INTERVAL '30 days', 'apt', 'Demo Feed', 'synthetic', 'DEMO-APT-01 campaign targets financial and tech sectors with multi-stage attack', 'Threat actor DEMO-APT-01 conducting coordinated campaign against MetaCorp, JPMorgan Demo, and Microsoft Demo.', 'CTI Advisory: DEMO-APT-01 threat group targeting financial and technology sectors using multi-stage attack chain. VICTIMS: MetaCorp Inc (2.9B records via CVE-2026-99001), JPMorgan Demo Bank (internal network via CVE-2026-99992), Microsoft Demo (Azure AD via CVE-2026-99993). ATTACK CHAIN: Phishing (CVE-2026-99001) -> webshell (DEMO-WEBSHELL-01) -> stealer (Raccoon) -> credentials -> lateral movement -> data exfiltration. IOCs: 198.51.100.50 (meta C2), 203.0.113.200 (jpm C2).', 'critical', 96, 95, 'TLP:CLEAR', ARRAY['apt','demo-apt-01','campaign','multi-stage','meta','jpmorgan','microsoft','demo'], jsonb_build_array(jsonb_build_object('type','actor','value','DEMO-APT-01'),jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','domain','value','jpmorgan-demo.invalid'),jsonb_build_object('type','domain','value','microsoft-demo.invalid'),jsonb_build_object('type','ip','value','198.51.100.50'),jsonb_build_object('type','ip','value','203.0.113.200'),jsonb_build_object('type','cve','value','CVE-2026-99001'),jsonb_build_object('type','cve','value','CVE-2026-99992'),jsonb_build_object('type','cve','value','CVE-2026-99993')), jsonb_build_array(jsonb_build_object('type','ip','value','198.51.100.50'),jsonb_build_object('type','ip','value','203.0.113.200')), jsonb_build_array(jsonb_build_object('type','targets','value','meta-corp.invalid'),jsonb_build_object('type','targets','value','jpmorgan-demo.invalid'),jsonb_build_object('type','targets','value','microsoft-demo.invalid')), '{"advisory_id":"DEMO-ADV-2026-001","attack_chain":["phishing","webshell","stealer","lateral-movement","data-exfil"]}'::jsonb, true, 'synthetic'),

  ('demo-evt-nexus-001', NOW()-INTERVAL '25 days', 'apt', 'Demo Feed', 'synthetic', 'NEXUS-THREAT abusing cloud trust relationships for cross-account access', 'NEXUS-THREAT group exploiting trust relationships between cloud accounts at Google Demo and Amazon Demo.', 'CTI Advisory: NEXUS-THREAT group exploiting trust relationships between GCP and AWS cloud accounts. Google Demo service account keys used to pivot to Amazon Demo AWS environment via shared OAuth patterns. MALWARE: NEXUS-STEALER-01 (google_stealer.py) and NEXUS-STEALER-02 (aws_keylogger.exe) both beacon to 198.51.100.75. GITHUB EXPOSURE: gh-google-001 (GCP key), gh-aws-001 (AWS key). DARKWEB: NEXUS-THREAT selling cloud access on versus_market and torrez_market.', 'critical', 94, 92, 'TLP:CLEAR', ARRAY['apt','nexus-threat','cloud','gcp','aws','cross-cloud','demo'], jsonb_build_array(jsonb_build_object('type','actor','value','NEXUS-THREAT'),jsonb_build_object('type','domain','value','google-demo.invalid'),jsonb_build_object('type','domain','value','amazon-demo.invalid'),jsonb_build_object('type','ip','value','198.51.100.75')), jsonb_build_array(jsonb_build_object('type','ip','value','198.51.100.75')), jsonb_build_array(jsonb_build_object('type','targets','value','google-demo.invalid'),jsonb_build_object('type','targets','value','amazon-demo.invalid')), '{}'::jsonb, true, 'synthetic'),

  -- Ransomware groups
  ('demo-evt-ransom-001', NOW()-INTERVAL '15 days', 'ransomware', 'Demo Feed', 'synthetic', 'DEMO-RANSOM-01 adds 3 new victims to leak site', 'Ransomware group DEMO-RANSOM-01 listed MetaCorp Inc, JPMorgan Demo Bank, and Steam Demo on darkweb leak site.', 'DEMO-RANSOM-01 (DeadboltDemo/LockIT) ransomware group expanded leak site with 3 new victims: 1) MetaCorp Inc - 2.9B records, ransom $5M, 2) JPMorgan Demo Bank - internal network access, ransom $3M, 3) Steam Demo Inc - 15M gaming accounts, ransom $500K. Demands range from $500K to $5M. Double-extortion model confirmed. LockIT ransomware builder used. C2: ransom-demo.onion.', 'critical', 93, 91, 'TLP:CLEAR', ARRAY['ransomware','demo-ransom-01','meta','jpmorgan','steam','leak-site','demo'], jsonb_build_array(jsonb_build_object('type','actor','value','DEMO-RANSOM-01'),jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','domain','value','jpmorgan-demo.invalid'),jsonb_build_object('type','domain','value','steam-demo.invalid')), jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid')), jsonb_build_array(jsonb_build_object('type','claims_victim','value','MetaCorp Inc'),jsonb_build_object('type','claims_victim','value','JPMorgan Demo Bank'),jsonb_build_object('type','claims_victim','value','Steam Demo Inc')), '{}'::jsonb, true, 'synthetic'),

  -- Combolist mega drop
  ('demo-evt-combo-001', NOW()-INTERVAL '10 days', 'combolist', 'Demo Feed', 'synthetic', 'Full cross-platform mega combo links all demo companies - 2M lines', '2 million line combolist compiled by DEMO-APT-01 linking credentials across all 15 demo companies.', 'Mega combo list (2M lines) compiled by DEMO-APT-01. Links credentials across all demo platforms: MetaCorp (meta-corp.invalid, 500K lines), Google (google-demo.invalid, 200K lines), Amazon (amazon-demo.invalid, 150K lines), Microsoft (microsoft-demo.invalid, 180K lines), JPMorgan (jpmorgan-demo.invalid, 100K lines), TikTok (tiktok-demo.invalid, 250K lines), Apple (apple-demo.invalid, 200K lines), Netflix (netflix-demo.invalid, 80K lines), Spotify (spotify-demo.invalid, 60K lines), PayPal (paypal-demo.invalid, 90K lines), LinkedIn (linkedin-demo.invalid, 120K lines), Steam (steam-demo.invalid, 40K lines), Uber (uber-demo.invalid, 30K lines), Salesforce (salesforce-demo.invalid, 35K lines). Format: email:pass@domain | Platform | verified=true. Distributed via Telegram @ShadowBroker channel (8000 members).', 'critical', 92, 94, 'TLP:CLEAR', ARRAY['combolist','mega-combo','2m-lines','telegram','demo-apt-01','all-platforms','demo'], jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','domain','value','google-demo.invalid'),jsonb_build_object('type','domain','value','amazon-demo.invalid'),jsonb_build_object('type','domain','value','microsoft-demo.invalid'),jsonb_build_object('type','actor','value','DEMO-APT-01')), jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid')), jsonb_build_array(jsonb_build_object('type','source','value','telegram-@ShadowBroker')), '{"line_count":2000000,"unique_domains":15,"source":"telegram","threat_actor":"DEMO-APT-01"}'::jsonb, true, 'synthetic'),

  -- Malware samples
  ('demo-evt-mal-001', NOW()-INTERVAL '45 days', 'malware', 'Demo Feed', 'synthetic', 'DEMO-WEBSHELL-01 linked to MetaCorp breach via CVE-2026-99001', 'Webshell used in MetaCorp breach identified as DEMO-WEBSHELL-01.', 'Malware sample: meta_webshell.php (SHA256: deadbeef0000000000000000000000000000000000000000000000000000000001). Family: DEMO-WEBSHELL-01. Used in MetaCorp breach via CVE-2026-99001 exploitation. Uploaded via /api/upload endpoint without authentication. Webshell at /uploads/shell.php allows RCE. C2: 198.51.100.50. Linked to DEMO-APT-01 and DEMO-RANSOM-01. Source: malwarebazaar.', 'high', 89, 94, 'TLP:CLEAR', ARRAY['malware','webshell','meta','cve-2026-99001','demo'], jsonb_build_array(jsonb_build_object('type','sha256','value','deadbeef0000000000000000000000000000000000000000000000000000000001'),jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','ip','value','198.51.100.50'),jsonb_build_object('type','actor','value','DEMO-APT-01')), jsonb_build_array(jsonb_build_object('type','sha256','value','deadbeef0000000000000000000000000000000000000000000000000000000001'),jsonb_build_object('type','domain','value','meta-corp.invalid')), jsonb_build_array(jsonb_build_object('type','used_in','value','meta-corp.invalid')), '{"file_type":"php","malware_family":"DEMO-WEBSHELL-01","source":"malwarebazaar"}'::jsonb, true, 'synthetic'),

  -- Phishing campaigns
  ('demo-evt-phish-001', NOW()-INTERVAL '44 days', 'phishing', 'Demo Feed', 'synthetic', 'Phishing campaign impersonates MetaCorp with credential harvesting kit', 'Phishing kit targeting MetaCorp credentials hosted at 198.51.100.50.', 'Phishing URL: https://secure-meta-login.invalid/auth/signin targeting MetaCorp users. Hosting IP: 198.51.100.50 (Russia). Sender: noreply@meta-corp-verify.invalid. Credential harvesting kit impersonates MetaCorp login page. Captures email and password, sends to C2 at 198.51.100.50. Multiple similar phishing URLs detected: meta-corp-verify.invalid/account, secure-meta-login.invalid/auth/signin. Linked to DEMO-APT-01 campaign. Source: openphish, phishtank.', 'high', 82, 90, 'TLP:CLEAR', ARRAY['phishing','meta','credential-harvesting','impersonation','demo'], jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','domain','value','secure-meta-login.invalid'),jsonb_build_object('type','ip','value','198.51.100.50')), jsonb_build_array(jsonb_build_object('type','domain','value','secure-meta-login.invalid'),jsonb_build_object('type','ip','value','198.51.100.50')), jsonb_build_array(jsonb_build_object('type','impersonates','value','MetaCorp')), '{"target_brand":"MetaCorp","phish_type":"credential_harvesting","active":true}'::jsonb, true, 'synthetic'),

  -- Actor profiles
  ('demo-evt-actor-001', NOW()-INTERVAL '120 days', 'apt', 'Demo Feed', 'synthetic', 'DEMO-APT-01 threat actor profile: ransomware and data theft specialist', 'Detailed profile of threat actor DEMO-APT-01.', 'Threat Actor Profile: DEMO-APT-01 (aliases: ShadowForge, IronWave). Prolific threat actor specializing in ransomware and data theft. TARGET SECTORS: Technology, Financial, Healthcare, Government. COUNTRIES: Russia, China. LINKED BREACHES: MetaCorp Inc (2.9B records), JPMorgan Demo Bank (internal network), Microsoft Demo Corp (Azure AD), Amazon Demo Inc (AWS). EXPLOITED CVES: CVE-2026-99001 (MetaCorp Fileshare Pro RCE), CVE-2026-99991 (Google Workspace SSO bypass). MALWARE: DEMO-WEBSHELL-01, DEMO-BACKDOOR-01, DEMO-LATERAL-01. IOCs: 198.51.100.50 (C2), 203.0.113.200 (C2). ATTACK METHODS: Phishing, exploit exploitation, stealer malware (Raccoon, Lumma), lateral movement.', 'high', 91, 95, 'TLP:CLEAR', ARRAY['apt','demo-apt-01','threat-actor','ransomware','profile','demo'], jsonb_build_array(jsonb_build_object('type','actor','value','DEMO-APT-01'),jsonb_build_object('type','cve','value','CVE-2026-99001'),jsonb_build_object('type','cve','value','CVE-2026-99991'),jsonb_build_object('type','malware','value','DEMO-WEBSHELL-01'),jsonb_build_object('type','malware','value','DEMO-BACKDOOR-01')), jsonb_build_array(jsonb_build_object('type','ip','value','198.51.100.50'),jsonb_build_object('type','ip','value','203.0.113.200')), jsonb_build_array(jsonb_build_object('type','linked_to','value','meta-corp.invalid'),jsonb_build_object('type','linked_to','value','jpmorgan-demo.invalid'),jsonb_build_object('type','linked_to','value','microsoft-demo.invalid')), '{"aliases":["ShadowForge","IronWave"],"sectors":["Technology","Financial","Healthcare","Government"],"countries":["Russia","China"]}'::jsonb, true, 'synthetic'),

  -- Paste site posts
