  ('demo-evt-stealer-001', NOW()-INTERVAL '30 days', 'stealer', 'Demo Feed', 'synthetic', 'Multi-stealer campaign captures credentials across all demo companies', 'Raccoon, RedLine, Lumma, Stealc, and Aurora stealer campaigns active across demo environment.', 'Stealer campaign summary: Raccoon (23 hosts, 5,234 creds), RedLine (15 hosts, 3,120 creds), Lumma (18 hosts, 4,567 creds), Stealc (12 hosts, 3,890 creds), Aurora (8 hosts, 1,234 creds), Vidar (6 hosts, 1,890 creds). TARGETED DOMAINS: meta-corp.invalid (10 hosts, 890 creds), jpmorgan-demo.invalid (6 hosts, 445 creds), google-demo.invalid (5 hosts, 340 creds), microsoft-demo.invalid (4 hosts, 298 creds), amazon-demo.invalid (4 hosts, 312 creds), tiktok-demo.invalid (4 hosts, 278 creds). All data synthetic and demonstratic.', 'high', 85, 88, 'TLP:CLEAR', ARRAY['stealer','raccoon','redline','lumma','stealc','credential','demo'], jsonb_build_array(jsonb_build_object('type','stealer','value','raccoon'),jsonb_build_object('type','stealer','value','redline'),jsonb_build_object('type','stealer','value','lumma'),jsonb_build_object('type','stealer','value','stealc'),jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','domain','value','jpmorgan-demo.invalid')), jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid')), jsonb_build_array(jsonb_build_object('type','captures_from','value','meta-corp.invalid'),jsonb_build_object('type','captures_from','value','jpmorgan-demo.invalid'),jsonb_build_object('type','captures_from','value','google-demo.invalid')), '{"total_hosts":82,"total_credentials":20563}'::jsonb, true, 'masked'),

