  ('demo-evt-correl-001', NOW()-INTERVAL '44 days', 'correlation', 'Demo Feed', 'synthetic', 'Full attack chain correlation: MetaCorp breach by DEMO-APT-01 via CVE-2026-99001 and Raccoon stealer', 'Complete attack chain from initial access to data exfiltration mapped across multiple sources.', 'ATTACK CHAIN ANALYSIS: MetaCorp breach by DEMO-APT-01: PHASE 1 - Recon: Threat actor scans for MetaCorp Fileshare Pro (CVE-2026-99001). PHASE 2 - Initial Access: CVE-2026-99001 exploited, webshell DEMO-WEBSHELL-01 uploaded at /uploads/shell.php. C2: 198.51.100.50. PHASE 3 - Discovery: Stealer malware (Raccoon) deployed via phishing email to admin.meta@demo.invalid. PHASE 4 - Collection: Raccoon captures 234 credentials from meta-host-001 including VPN, FileShare, and cloud creds. PHASE 5 - Lateral Movement: Domain admin access via it.admin credentials. PHASE 6 - Exfiltration: 2.9B records exfiltrated over 48h. PHASE 7 - Extortion: Data posted on darkweb, DEMO-RANSOM-01 leak site. CORRELATED IOCs: meta-corp.invalid, 198.51.100.50, deadbeef..., admin.meta@demo.invalid, CVE-2026-99001.', 'critical', 97, 96, 'TLP:CLEAR', ARRAY['correlation','attack-chain','meta','demo-apt-01','cve-2026-99001','raccoon','full-analysis','demo'], jsonb_build_array(jsonb_build_object('type','actor','value','DEMO-APT-01'),jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','cve','value','CVE-2026-99001'),jsonb_build_object('type','ip','value','198.51.100.50'),jsonb_build_object('type','malware','value','Raccoon'),jsonb_build_object('type','malware','value','DEMO-WEBSHELL-01'),jsonb_build_object('type','actor','value','DEMO-RANSOM-01')), jsonb_build_array(jsonb_build_object('type','domain','value','meta-corp.invalid'),jsonb_build_object('type','ip','value','198.51.100.50')), jsonb_build_array(jsonb_build_object('type','attack_chain_for','value','meta-corp.invalid')), '{}'::jsonb, true, 'synthetic'),

  ('demo-evt-correl-002', NOW()-INTERVAL '35 days', 'correlation', 'Demo Feed', 'synthetic', 'Full attack chain correlation: JPMorgan Demo Bank breach by ALPHV/BlackCat', 'Complete attack chain for JPMorgan Demo Bank financial sector breach.', 'ATTACK CHAIN ANALYSIS: JPMorgan Demo Bank breach by ALPHV/BlackCat: PHASE 1 - Initial Access: SQL injection (CVE-2026-99992) in trading platform order submission endpoint. PHASE 2 - Foothold: Vidar stealer deployed on jpm-host-002. PHASE 3 - Credential Harvest: 145 creds captured including Bloomberg Terminal (bloomberg.user@demo.invalid), trading system access. PHASE 4 - Privilege Escalation: Raccoon captures domain admin from jpm-host-003 (298 creds, it.operations@demo.invalid). PHASE 5 - Lateral Movement: Internal network access via Active Directory. PHASE 6 - Data Access: Bloomberg Terminal data, trading algorithms, risk dashboards accessed. PHASE 7 - Extortion: ALPHV auction on darkweb, starting $75K. C2: 203.0.113.200. CORRELATED IOCs: jpmorgan-demo.invalid, 203.0.113.200, CVE-2026-99992, Vidar stealer.', 'critical', 96, 94, 'TLP:CLEAR', ARRAY['correlation','attack-chain','jpmorgan','alphv','cve-2026-99992','vidar','full-analysis','demo'], jsonb_build_array(jsonb_build_object('type','actor','value','ALPHV/BlackCat'),jsonb_build_object('type','domain','value','jpmorgan-demo.invalid'),jsonb_build_object('type','cve','value','CVE-2026-99992'),jsonb_build_object('type','ip','value','203.0.113.200'),jsonb_build_object('type','malware','value','Vidar'),jsonb_build_object('type','malware','value','Raccoon')), jsonb_build_array(jsonb_build_object('type','domain','value','jpmorgan-demo.invalid'),jsonb_build_object('type','ip','value','203.0.113.200')), jsonb_build_array(jsonb_build_object('type','attack_chain_for','value','jpmorgan-demo.invalid')), '{}'::jsonb, true, 'synthetic');

